    20→static inline uint64_t d2u(double d)
    21→{
    22→    union { double d; uint64_t u; } x;
    23→    x.d = d;
    24→    return x.u;
    25→}
    26→
    27→static inline double u2d(uint64_t u)
    28→{
    29→    union { double d; uint64_t u; } x;
    30→    x.u = u;
    31→    return x.d;
    32→}
    33→
    34→static volatile double g_acc;
    35→
    36→static void emit(double x)
    37→{
    38→#ifdef EN_PERF
    39→    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    40→    g_acc += ceil(vx);
    41→#else
    42→    double r = ceil(x);
    43→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    44→#endif
    45→}
    46→
    47→static void emit_u(uint64_t bits)
    48→{
    49→    emit(u2d(bits));
    50→}
    51→
    52→/* ------------------------------------------------------------------ */
    53→/* test_representative_100: 100 representative inputs for ceil()      */
    54→/* ------------------------------------------------------------------ */
    55→
    56→static void test_representative_100(void)
    57→{
    58→    /* --- Section 1: Special IEEE 754 values (7) --- */
    59→    emit(0.0);
    60→    emit(-0.0);
    61→    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    62→    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    63→    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    64→    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    65→    emit_u(0xfff0000000000000ULL);  /* -Inf */
    66→
    67→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    68→    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    69→    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    70→    emit_u(0x0008000000000000ULL);  /* mid subnormal */
    71→    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    72→    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    73→    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */
    74→
    75→    /* --- Section 3: Normal boundary values (6) --- */
    76→    emit(DBL_MIN);                  /* 2^-1022, smallest positive normal */
    77→    emit(-DBL_MIN);
    78→    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    79→    emit(DBL_MAX);                  /* largest finite double */
    80→    emit(-DBL_MAX);
    81→    emit_u(0x7feeffffffffffffULL);  /* one ULP below DBL_MAX */
    82→
    83→    /* --- Section 4: Near 1.0 ULP density (8) --- */
    84→    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0: ceil -> 1.0 */
    85→    emit(1.0);
    86→    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0: ceil -> 2.0 */
    87→    emit_u(0x3feffffffffffffeULL);  /* two ULPs below 1.0: ceil -> 1.0 */
    88→    emit_u(0x3ff0000000000002ULL);  /* two ULPs above 1.0: ceil -> 2.0 */
    89→    emit(-1.0);
    90→    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0: ceil -> 0.0 */
    91→    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0: ceil -> -1.0 */
    92→
    93→    /* --- Section 5: Exact integers positive and negative (10) --- */
    94→    emit(2.0);
    95→    emit(3.0);
    96→    emit(4.0);
    97→    emit(5.0);
    98→    emit(100.0);
    99→    emit(-2.0);
   100→    emit(-3.0);
   101→    emit(-4.0);
   102→    emit(-5.0);
   103→    emit(-100.0);
   104→
   105→    /* --- Section 6: Half-integer values n+0.5 (10) --- */
   106→    emit(0.5);
   107→    emit(1.5);
   108→    emit(2.5);
   109→    emit(3.5);
   110→    emit(10.5);
   111→    emit(-0.5);
   112→    emit(-1.5);
   113→    emit(-2.5);
   114→    emit(-3.5);
   115→    emit(-10.5);
   116→
   117→    /* --- Section 7: ULP neighbors of exact integers (12) --- */
   118→    emit_u(0x3ff0000000000000ULL);  /* exactly 1.0: ceil -> 1.0 */
   119→    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0: ceil -> 2.0 */
   120→    emit_u(0x400fffffffffffffULL);  /* one ULP below 4.0: ceil -> 4.0 */
   121→    emit_u(0x4010000000000001ULL);  /* one ULP above 4.0: ceil -> 5.0 */
   122→    emit_u(0xbfefffffffffffffULL);  /* closest double below 0 from -side of 1: ceil -> 0.0 */
   123→    emit_u(0xbff0000000000001ULL);  /* one ULP below -1.0: ceil -> -1.0 */
   124→    emit_u(0x4340000000000000ULL);  /* 2^53: smallest double with no fractional bits */
   125→    emit_u(0x433fffffffffffffULL);  /* one ULP below 2^53: has fractional part */
   126→    emit_u(0xc340000000000000ULL);  /* -2^53: exact integer */
   127→    emit_u(0xc33fffffffffffffULL);  /* one ULP toward zero from -2^53: has fractional part */
   128→    emit_u(0x4330000000000000ULL);  /* 2^52: boundary where all doubles are integers */
   129→    emit_u(0xc330000000000000ULL);  /* -2^52 */
   130→
   131→    /* --- Section 8: Fractional inputs with various tenths (16) --- */
   132→    emit(0.1);
   133→    emit(0.2);
   134→    emit(0.3);
   135→    emit(0.4);
   136→    emit(0.6);
   137→    emit(0.7);
   138→    emit(0.8);
   139→    emit(0.9);
   140→    emit(-0.1);
   141→    emit(-0.2);
   142→    emit(-0.3);
   143→    emit(-0.4);
   144→    emit(-0.6);
   145→    emit(-0.7);
   146→    emit(-0.8);
   147→    emit(-0.9);
   148→
   149→    /* --- Section 9: Large values where double has no fractional bits (10) --- */
   150→    emit(1.0e15);    /* within integer-exact range of double */
   151→    emit(-1.0e15);
   152→    emit(1.0e16);    /* still exactly representable as integer */
   153→    emit(-1.0e16);
   154→    emit(1.0e100);   /* very large: already an integer */
   155→    emit(-1.0e100);
   156→    emit(1.0e300);
   157→    emit(-1.0e300);
   158→    emit_u(0x4350000000000000ULL);  /* 2^54: integer with no fractional bits */
   159→    emit_u(0xc350000000000000ULL);  /* -2^54 */
   160→
   161→    /* --- Section 10: Near-zero and tiny positive/negative (15) --- */
   162→    emit(1.0e-10);
   163→    emit(-1.0e-10);
   164→    emit(1.0e-100);
   165→    emit(-1.0e-100);
   166→    emit(1.0e-200);
   167→    emit(-1.0e-200);
   168→    emit(0.0000000000001);   /* tiny positive: ceil -> 1.0 */
   169→    emit(-0.0000000000001);  /* tiny negative: ceil -> 0.0 */
   170→    emit(0.4999999999999);   /* just below 0.5: ceil -> 1.0 */
   171→    emit(0.5000000000001);   /* just above 0.5: ceil -> 1.0 */
   172→    emit(-0.4999999999999);  /* just above -0.5 toward zero: ceil -> 0.0 */
   173→    emit(-0.5000000000001);  /* just below -0.5 away from zero: ceil -> 0.0 */
   174→    emit(0.9999999999999);   /* just below 1.0: ceil -> 1.0 */
   175→    emit(1.0000000000001);   /* just above 1.0: ceil -> 2.0 */
   176→    emit(-0.9999999999999);  /* just above -1.0 toward zero: ceil -> 0.0 */
   177→}
