   181→#ifndef EN_PERF
   182→/* Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
   183→static void test_sweep(void)
   184→{
   185→    double hi = 10.0;
   186→    int nsteps = 100;
   187→    double step = hi / (double)nsteps;
   188→
   189→    /* [0, 10] */
   190→    for (int i = 0; i <= nsteps; i++)
   191→        emit((double)i * step);
   192→
   193→    /* [-10, 0] */
   194→    for (int i = 0; i <= nsteps; i++)
   195→        emit(-hi + (double)i * step);
   196→}
   197→
   198→/* Sample [0, 10] every ~0.05 (200 points) */
   199→static void test_exhaustive_small(void)
   200→{
   201→    double hi = 10.0;
   202→    int nsteps = 200;
   203→    double step = hi / (double)nsteps;
   204→
   205→    for (int i = 0; i <= nsteps; i++)
   206→        emit((double)i * step);
   207→}
   208→#endif /* !EN_PERF */
   209→
   210→/* ------------------------------------------------------------------ */
   211→
   212→int main(void)
   213→{
   214→#ifdef EN_PERF
   215→    startPFM;
   216→    test_representative_100();
   217→    stopPFM;
   218→    readResult();
   219→    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
   220→#else
   221→    test_representative_100();
   222→    test_sweep();
   223→    test_exhaustive_small();
   224→#endif
   225→    return 0;
   226→}
